def compute_unwinding_summary(df_atm8):
    """Summarise CE/PE unwinding + parallel winding from ATM±5 strikes."""
    if df_atm8 is None or len(df_atm8) == 0:
        return None
    ce_unwind, pe_unwind, ce_build, pe_build = [], [], [], []
    parallel_pairs = []
    for _, row in df_atm8.iterrows():
        strike = row.get('strikePrice', 0)
        chg_ce = row.get('changeinOpenInterest_CE', 0) or 0
        chg_pe = row.get('changeinOpenInterest_PE', 0) or 0
        ce_act = 'Unwinding' if chg_ce < -1000 else 'Buildup' if chg_ce > 1000 else 'Flat'
        pe_act = 'Unwinding' if chg_pe < -1000 else 'Buildup' if chg_pe > 1000 else 'Flat'
        if ce_act == 'Unwinding':
            ce_unwind.append({'strike': strike, 'chg': chg_ce})
        elif ce_act == 'Buildup':
            ce_build.append({'strike': strike, 'chg': chg_ce})
        if pe_act == 'Unwinding':
            pe_unwind.append({'strike': strike, 'chg': chg_pe})
        elif pe_act == 'Buildup':
            pe_build.append({'strike': strike, 'chg': chg_pe})
        if ce_act == 'Unwinding' and pe_act == 'Buildup':
            parallel_pairs.append({'strike': strike, 'type': 'CE Unwind + PE Buildup', 'impact': 'Bullish Shift'})
        elif pe_act == 'Unwinding' and ce_act == 'Buildup':
            parallel_pairs.append({'strike': strike, 'type': 'PE Unwind + CE Buildup', 'impact': 'Bearish Shift'})
        elif ce_act == 'Unwinding' and pe_act == 'Unwinding':
            parallel_pairs.append({'strike': strike, 'type': 'Both Unwinding', 'impact': 'Expiry Exit'})
        elif ce_act == 'Buildup' and pe_act == 'Buildup':
            parallel_pairs.append({'strike': strike, 'type': 'Both Buildup', 'impact': 'High Activity'})
    bull_parallel = [p for p in parallel_pairs if p['impact'] == 'Bullish Shift']
    bear_parallel = [p for p in parallel_pairs if p['impact'] == 'Bearish Shift']
    if bull_parallel and len(bull_parallel) >= len(bear_parallel):
        verdict = f"⚡ BULLISH PARALLEL WINDING ({len(bull_parallel)} strikes)"
    elif bear_parallel and len(bear_parallel) > len(bull_parallel):
        verdict = f"⚡ BEARISH PARALLEL WINDING ({len(bear_parallel)} strikes)"
    elif len(ce_unwind) > len(pe_unwind) and len(ce_unwind) >= 2:
        verdict = f"🔄 CE UNWINDING dominant ({len(ce_unwind)} strikes) → Bullish"
    elif len(pe_unwind) > len(ce_unwind) and len(pe_unwind) >= 2:
        verdict = f"🔄 PE UNWINDING dominant ({len(pe_unwind)} strikes) → Bearish"
    else:
        verdict = "Balanced / No strong unwinding"
    def _top(lst, rev=False):
        if not lst:
            return "None"
        sorted_lst = sorted(lst, key=lambda x: -abs(x['chg']) if rev else x['chg'])[:3]
        return ", ".join([f"{int(l['strike'])}({l['chg']/1000:+.0f}K)" for l in sorted_lst])
    return {
        'ce_unwind_count': len(ce_unwind),
        'pe_unwind_count': len(pe_unwind),
        'ce_build_count': len(ce_build),
        'pe_build_count': len(pe_build),
        'parallel_count': len(parallel_pairs),
        'bull_parallel': len(bull_parallel),
        'bear_parallel': len(bear_parallel),
        'ce_unwind_top': _top(ce_unwind),
        'pe_unwind_top': _top(pe_unwind),
        'ce_build_top': _top(ce_build, rev=True),
        'pe_build_top': _top(pe_build, rev=True),
        'verdict': verdict,
    }

def check_pcr_sr_proximity_alert(underlying_price, proximity_pts=25):
    """Fire a Telegram alert when spot is within proximity_pts of any PCR S/R level.
    Uses the same _pcr_sr_snapshot stored by the UI — identical data to what's displayed."""
    snapshot = getattr(st.session_state, '_pcr_sr_snapshot', [])
    if not snapshot:
        return
    alerted = st.session_state.setdefault('_pcr_proximity_alerted', {})
    for _s in snapshot:
        label = _s['label']
        pcr_val = _s['pcr']
        sr_type = _s['type']
        if 'Neutral' in sr_type:
            continue
        level = _s['level']
        dist = abs(underlying_price - level)
        if dist > proximity_pts:
            # Reset alert when price moves away (>20 pts buffer)
            if dist > 20:
                alerted.pop(label, None)
            continue
        # Already alerted this level recently?
        last_alert = alerted.get(label)
        if last_alert and (datetime.now(pytz.timezone('Asia/Kolkata')) - last_alert).total_seconds() < 1800:
            continue
        sr_clean = sr_type.replace('🔴', '').replace('🟢', '').replace('⚪', '').strip()
        zone_low  = f"₹{level - proximity_pts:.0f}"
        zone_high = f"₹{level + proximity_pts:.0f}"
        if sr_clean == 'Resistance':
            msg = f"⚠️ PCR RESISTANCE near ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {datetime.now(pytz.timezone('Asia/Kolkata')).strftime('%H:%M IST')}"
        else:
            msg = f"⚠️ PCR SUPPORT near ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {datetime.now(pytz.timezone('Asia/Kolkata')).strftime('%H:%M IST')}"
        alerted[label] = datetime.now(pytz.timezone('Asia/Kolkata'))
        return msg
    return None


def send_candle_at_sr_alert(candle, underlying_price, pcr_sr_snapshot, support_levels, resistance_levels, proximity_pts=50):
    """Fire when a bullish candle forms at support or bearish candle forms at resistance.
    Independent of score — fires on pattern+location match alone. Cooldown 30 min per level."""
    def _e(v): return str(v).replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
    direction = candle.get('direction', '')
    pattern = candle.get('pattern', 'No Pattern')
    if direction not in ('Bullish', 'Bearish') or pattern in ('No Pattern', 'N/A', ''):
        return
    alerted = st.session_state.setdefault('_candle_sr_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))

    # Build candidate levels: PCR S/R + OC levels.
    # Neutral PCR strikes are included as positional S/R (below spot → support, above → resistance)
    # so alerts fire even when no strike has extreme PCR.
    candidate_supports = []
    candidate_resistances = []
    for s in (pcr_sr_snapshot or []):
        sr_clean = s['type'].replace('🔴','').replace('🟢','').replace('⚪','').strip()
        level = s['level']
        if sr_clean == 'Support':
            candidate_supports.append(('PCR', s['label'], level))
        elif sr_clean == 'Resistance':
            candidate_resistances.append(('PCR', s['label'], level))
        else:
            # Neutral strike — use position relative to spot as weak S/R
            if level <= underlying_price:
                candidate_supports.append(('PCR-N', s['label'], level))
            else:
                candidate_resistances.append(('PCR-N', s['label'], level))
    for lvl in (support_levels or []):
        candidate_supports.append(('OC', f"₹{lvl:.0f}", lvl))
    for lvl in (resistance_levels or []):
        candidate_resistances.append(('OC', f"₹{lvl:.0f}", lvl))

    time_str = now.strftime('%H:%M:%S IST')
    if direction == 'Bullish':
        for src, lbl, level in candidate_supports:
            if abs(underlying_price - level) > proximity_pts:
                continue
            key = f"candle_bull_{level:.0f}"
            last = alerted.get(key)
            if last and (now - last).total_seconds() < 1800:
                continue
            msg = f"🕯 BULLISH CANDLE at Support ₹{level:.0f} | {_e(pattern)} | Spot ₹{underlying_price:.0f} | {time_str}"
            alerted[key] = now
            return msg
    elif direction == 'Bearish':
        for src, lbl, level in candidate_resistances:
            if abs(underlying_price - level) > proximity_pts:
                continue
            key = f"candle_bear_{level:.0f}"
            last = alerted.get(key)
            if last and (now - last).total_seconds() < 1800:
                continue
            msg = f"🕯 BEARISH CANDLE at Resistance ₹{level:.0f} | {_e(pattern)} | Spot ₹{underlying_price:.0f} | {time_str}"
            alerted[key] = now
            return msg
    return None


def send_retest_alert(underlying_price, pcr_sr_snapshot, support_levels, resistance_levels, proximity_pts=30):
    """Fire when spot retests a previously broken S/R level.
    Tracks which side of each level spot was on last cycle and alerts when it returns to the level."""
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    time_str = now.strftime('%H:%M:%S IST')

    # Build all S/R candidate levels
    levels = []
    for s in (pcr_sr_snapshot or []):
        sr_clean = s['type'].replace('🔴','').replace('🟢','').replace('⚪','').strip()
        if sr_clean in ('Support', 'Resistance'):
            levels.append((s['level'], sr_clean, s['label']))
        else:
            tag = 'Support' if s['level'] <= underlying_price else 'Resistance'
            levels.append((s['level'], tag, s['label']))
    for lvl in (support_levels or []):
        levels.append((lvl, 'Support', f"₹{lvl:.0f}"))
    for lvl in (resistance_levels or []):
        levels.append((lvl, 'Resistance', f"₹{lvl:.0f}"))

    if not levels:
        return None

    # Session state: track last known side (above/below) for each level
    _sides = st.session_state.setdefault('_retest_side', {})
    _alerted = st.session_state.setdefault('_retest_alerted', {})
    msgs = []

    for level, sr_type, lbl in levels:
        key = f"{level:.0f}"
        current_side = 'above' if underlying_price > level else 'below'
        prev_side = _sides.get(key)
        _sides[key] = current_side

        if prev_side is None or prev_side == current_side:
            continue  # no crossover yet, or no history

        # A crossover happened — spot just crossed back to the level (retest)
        dist = abs(underlying_price - level)
        if dist > proximity_pts:
            continue

        last_alert = _alerted.get(key)
        if last_alert and (now - last_alert).total_seconds() < 900:
            continue  # 15 min cooldown

        if prev_side == 'above' and current_side == 'below':
            # Price just dropped below the level
            if sr_type == 'Support':
                msgs.append(f"🔴 <b>BREAKDOWN</b> ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {lbl} | {time_str}\n→ Price broke below support — breakdown risk ↑")
            else:
                msgs.append(f"🔁 <b>RETEST (RESISTANCE)</b> ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {lbl} | {time_str}\n→ Price returning to resistance from above — watch for rejection")
            _alerted[key] = now
        elif prev_side == 'below' and current_side == 'above':
            # Price just rose above the level
            if sr_type == 'Resistance':
                msgs.append(f"🚀 <b>BREAKOUT</b> ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {lbl} | {time_str}\n→ Price broke above resistance — breakout risk ↑")
            else:
                msgs.append(f"🔁 <b>RETEST (SUPPORT)</b> ₹{level:.0f} | Spot ₹{underlying_price:.0f} | {lbl} | {time_str}\n→ Price returning to support from below — watch for bounce")
            _alerted[key] = now

    return "\n\n".join(msgs) if msgs else None


def send_capping_at_sr_alert(sa_result, underlying_price, proximity_pts=25, sr_prox_pts=25):
    """Fire when sudden call capping or put support is detected at S/R.
    Per user rule: NIFTY spot must be at the matching side of a major S/R zone:
      - CALL CAPPING (resistance writing) → spot near a major RESISTANCE
      - PUT WRITING / CAPPING (support writing) → spot near a major SUPPORT
    Cooldown 30 min per strike."""
    def _e(v): return str(v).replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
    if sa_result is None:
        return
    adf = sa_result.get('analysis_df')
    if adf is None:
        return
    alerted = st.session_state.setdefault('_capping_sr_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    time_str = now.strftime('%H:%M:%S IST')

    msgs = []

    # Call capping (resistance writing) — fires on ANY detected event
    # (S/R-side gating removed per user request).
    try:
        cap_rows = adf[
            adf['Call_Class'].isin(['High Conviction Resistance', 'Strong Resistance']) &
            adf['Call_Activity'].isin(['Writing (Vol Confirmed)', 'Writing (Resistance)'])
        ]
        for _, r in cap_rows.iterrows():
            strike = float(r['Strike'])
            if abs(underlying_price - strike) > proximity_pts:
                continue
            key = f"cap_call_{strike:.0f}"
            last = alerted.get(key)
            if last and (now - last).total_seconds() < 1800:
                continue
            vol_tag = "🔥 Vol Confirmed" if r.get('CE_Vol_High', False) else ""
            oi_l = float(r.get('CE_OI', 0) or 0) / 100000
            msgs.append(
                f"🟥 <b>CALL CAPPING ₹{strike:.0f}</b> "
                f"{vol_tag} | OI {oi_l:.1f}L | Spot ₹{underlying_price:.0f} | {time_str}"
            )
            alerted[key] = now
    except Exception:
        pass

    # Put writing / capping (support writing) — fires on ANY detected event
    # (S/R-side gating removed per user request).
    try:
        sup_rows = adf[
            adf['Put_Class'].isin(['High Conviction Support', 'Strong Support']) &
            adf['Put_Activity'].isin(['Writing (Vol Confirmed)', 'Writing (Support)'])
        ]
        for _, r in sup_rows.iterrows():
            strike = float(r['Strike'])
            if abs(underlying_price - strike) > proximity_pts:
                continue
            key = f"cap_put_{strike:.0f}"
            last = alerted.get(key)
            if last and (now - last).total_seconds() < 1800:
                continue
            vol_tag = "🔥 Vol Confirmed" if r.get('PE_Vol_High', False) else ""
            oi_l = float(r.get('PE_OI', 0) or 0) / 100000
            msgs.append(
                f"🟩 <b>PUT WRITING ₹{strike:.0f}</b> "
                f"{vol_tag} | OI {oi_l:.1f}L | Spot ₹{underlying_price:.0f} | {time_str}"
            )
            alerted[key] = now
    except Exception:
        pass

    return "\n\n".join(msgs) if msgs else None


def send_decapping_alert(underlying_price, pcr_sr_snapshot=None, support_levels=None, resistance_levels=None, proximity_pts=30):
    """Fire Telegram alert when an ATM±2 strike shows CE/PE OI shedding or building.
    Only fires when spot is near an S/R level (not mid-range). Cooldown: 10 min per strike."""
    _decap_atm = getattr(st.session_state, '_decap_atm_data', [])
    if not _decap_atm:
        return None

    # Gate: only alert when spot is within proximity_pts of an S/R level
    _sr_levels = [s['level'] for s in (pcr_sr_snapshot or []) if s.get('level')]
    _sr_levels += list(support_levels or [])
    _sr_levels += list(resistance_levels or [])
    if not _sr_levels or not any(abs(underlying_price - lvl) <= proximity_pts for lvl in _sr_levels):
        return None

    _alerted = st.session_state.setdefault('_decap_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    time_str = now.strftime('%H:%M:%S IST')
    msgs = []

    for _e in _decap_atm:
        if _e.get('ce_decapping'):
            _key = f"decap_ce_{_e['strike']:.0f}"
            if not _alerted.get(_key) or (now - _alerted[_key]).total_seconds() > 600:
                msgs.append(
                    f"⚡ <b>DECAPPING {_e['label']} ₹{_e['strike']:.0f}</b>\n"
                    f"CE OI shed <b>{_e['ce_shed_pct']:.1f}%</b> "
                    f"({_e.get('prev_ce_oi_l',0):.1f}L → {_e['ce_oi_l']:.1f}L)\n"
                    f"→ Ceiling lifting → breakout risk ↑ | Spot ₹{underlying_price:.0f} | {time_str}"
                )
                _alerted[_key] = now

        if _e.get('pe_depeg'):
            _key = f"depeg_pe_{_e['strike']:.0f}"
            if not _alerted.get(_key) or (now - _alerted[_key]).total_seconds() > 600:
                msgs.append(
                    f"⚡ <b>DEPEG {_e['label']} ₹{_e['strike']:.0f}</b>\n"
                    f"PE OI shed <b>{_e['pe_shed_pct']:.1f}%</b> "
                    f"({_e.get('prev_pe_oi_l',0):.1f}L → {_e['pe_oi_l']:.1f}L)\n"
                    f"→ Floor dropping → breakdown risk ↑ | Spot ₹{underlying_price:.0f} | {time_str}"
                )
                _alerted[_key] = now

        if _e.get('ce_capping') and _e.get('ce_built_pct', 0) >= 1.0:
            _key = f"cap_ce_{_e['strike']:.0f}"
            if not _alerted.get(_key) or (now - _alerted[_key]).total_seconds() > 600:
                msgs.append(
                    f"⚡ <b>CALL CAPPING {_e['label']} ₹{_e['strike']:.0f}</b>\n"
                    f"CE OI built <b>{_e['ce_built_pct']:.1f}%</b> "
                    f"({_e.get('prev_ce_oi_l',0):.1f}L → {_e['ce_oi_l']:.1f}L)\n"
                    f"→ Ceiling forming → resistance ↑ | Spot ₹{underlying_price:.0f} | {time_str}"
                )
                _alerted[_key] = now

        if _e.get('pe_capping') and _e.get('pe_built_pct', 0) >= 1.0:
            _key = f"cap_pe_{_e['strike']:.0f}"
            if not _alerted.get(_key) or (now - _alerted[_key]).total_seconds() > 600:
                msgs.append(
                    f"⚡ <b>PUT CAPPING {_e['label']} ₹{_e['strike']:.0f}</b>\n"
                    f"PE OI built <b>{_e['pe_built_pct']:.1f}%</b> "
                    f"({_e.get('prev_pe_oi_l',0):.1f}L → {_e['pe_oi_l']:.1f}L)\n"
                    f"→ Floor forming → support ↑ | Spot ₹{underlying_price:.0f} | {time_str}"
                )
                _alerted[_key] = now

    return "\n\n".join(msgs) if msgs else None


def send_ob_zone_alert(ob_data, underlying_price, proximity_pts=30):
    """Fire a Telegram alert when price enters an active Order Block zone. Cooldown: 15 min per zone."""
    if not ob_data:
        return None
    _alerted = st.session_state.setdefault('_ob_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    time_str = now.strftime('%H:%M:%S IST')
    msgs = []

    for _obs, _emoji, _label, _action in [
        (ob_data.get('bullish_obs', []), '🟩', 'BULLISH', 'BUY — demand zone holding'),
        (ob_data.get('bearish_obs', []), '🟥', 'BEARISH', 'SELL — supply zone holding'),
    ]:
        for _ob in _obs:
            _ob_lo, _ob_hi, _ob_avg = _ob['low'], _ob['high'], _ob['avg']
            # Price inside or within proximity_pts of the OB zone
            _inside = _ob_lo <= underlying_price <= _ob_hi
            _near   = abs(underlying_price - _ob_avg) <= proximity_pts
            if not (_inside or _near):
                continue
            _key = f"ob_{_label}_{_ob_lo:.0f}_{_ob_hi:.0f}"
            _last = _alerted.get(_key)
            if _last and (now - _last).total_seconds() < 900:
                continue
            _status = '⚡ Price INSIDE zone' if _inside else f'⚡ Price {abs(underlying_price - _ob_avg):.0f}pts from zone'
            msgs.append(
                f"{_emoji} <b>ORDER BLOCK DETECTED — {_label} OB</b>\n"
                f"Zone: ₹{_ob_lo:.0f} – ₹{_ob_hi:.0f} | Avg ₹{_ob_avg:.0f}\n"
                f"{_status} | Spot ₹{underlying_price:.0f}\n"
                f"Action: {_action}\n"
                f"{time_str}"
            )
            _alerted[_key] = now

    return "\n\n".join(msgs) if msgs else None


def send_rejection_alert(candle, underlying_price, df_5m, sa_result, pcr_sr_snapshot, support_levels, resistance_levels, proximity_pts=25):
    """Detect and alert price rejection at ceiling (resistance) or floor (support).

    Rejection confirmed when at least 2 of 3 signals agree:
      Chart  — bearish wick (upper wick > body) at ceiling / bullish wick at floor,
               OR a bearish/bullish candle pattern
      OC     — CE ChgOI building at resistance OR PE ChgOI building at support
      Depth  — BidAskPressure bearish at ceiling / bullish at floor

    Cooldown: 10 min per level.
    """
    def _e(v): return str(v).replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
    alerted = st.session_state.setdefault('_rejection_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    time_str = now.strftime('%H:%M:%S IST')

    # ── Chart signal ──────────────────────────────────────────────────────────
    chart_bear = False  # rejection wick or pattern at ceiling
    chart_bull = False  # bounce wick or pattern at floor
    wick_detail = ''
    try:
        if df_5m is not None and len(df_5m) >= 1:
            last = df_5m.iloc[-1]
            o, h, l, c = float(last['open']), float(last['high']), float(last['low']), float(last['close'])
            body = abs(c - o)
            upper_wick = h - max(o, c)
            lower_wick = min(o, c) - l
            total_range = h - l if h > l else 1
            if upper_wick > body and upper_wick / total_range > 0.35:
                chart_bear = True
                wick_detail = f"Upper wick {upper_wick:.0f}pts ({upper_wick/total_range*100:.0f}% of range)"
            if lower_wick > body and lower_wick / total_range > 0.35:
                chart_bull = True
                wick_detail = f"Lower wick {lower_wick:.0f}pts ({lower_wick/total_range*100:.0f}% of range)"
        pat = candle.get('pattern', '')
        cdir = candle.get('direction', '')
        bearish_patterns = {'Bearish Engulfing','Shooting Star','Bearish Harami','Evening Star',
                            'Tweezer Top','Strong Red Candle','Pin Bar'}
        bullish_patterns = {'Bullish Engulfing','Hammer','Bullish Harami','Morning Star',
                            'Tweezer Bottom','Strong Green Candle','Pin Bar'}
        if pat in bearish_patterns or cdir == 'Bearish':
            chart_bear = True
        if pat in bullish_patterns or cdir == 'Bullish':
            chart_bull = True
    except Exception:
        pass

    # ── OC signal: CE/PE ChgOI at the strike ─────────────────────────────────
    oc_bear_strikes = {}   # strike → chg_oi for fresh CE writing
    oc_bull_strikes = {}   # strike → chg_oi for fresh PE writing
    try:
        adf = (sa_result or {}).get('analysis_df')
        if adf is not None:
            for _, r in adf.iterrows():
                sk = float(r['Strike'])
                chg_ce = float(r.get('changeinOpenInterest_CE', 0) or 0)
                chg_pe = float(r.get('changeinOpenInterest_PE', 0) or 0)
                if chg_ce > 5000:   # fresh call writing
                    oc_bear_strikes[sk] = chg_ce
                if chg_pe > 5000:   # fresh put writing
                    oc_bull_strikes[sk] = chg_pe
    except Exception:
        pass

    # ── Depth signal: BidAskPressure from analysis_df ─────────────────────────
    depth_bear_strikes = set()
    depth_bull_strikes = set()
    try:
        adf = (sa_result or {}).get('analysis_df')
        if adf is not None and 'BidAskPressure' in adf.columns:
            for _, r in adf.iterrows():
                sk = float(r['Strike'])
                bap = float(r.get('BidAskPressure', 0) or 0)
                if bap < -500:
                    depth_bear_strikes.add(sk)
                elif bap > 500:
                    depth_bull_strikes.add(sk)
    except Exception:
        pass

    # ── Find STRONGEST S/R only (highest OI strike near price) ───────────────
    # Only check rejection at the single strongest ceiling and strongest floor
    strongest_res = None   # (src, lbl, level, strike)
    strongest_sup = None
    try:
        adf = (sa_result or {}).get('analysis_df')
        if adf is not None:
            # Strongest resistance: highest CE OI above price within 3× proximity
            res_rows = adf[adf['Strike'] >= underlying_price - proximity_pts].copy()
            if not res_rows.empty and 'CE_OI' in res_rows.columns:
                res_rows = res_rows[res_rows['CE_OI'] == res_rows['CE_OI'].max()]
                if not res_rows.empty:
                    sk = float(res_rows.iloc[0]['Strike'])
                    oi = float(res_rows.iloc[0]['CE_OI'])
                    strongest_res = ('OC', f"₹{sk:.0f} OI:{oi/100000:.1f}L", sk, int(sk))
            # Strongest support: highest PE OI below price within 3× proximity
            sup_rows = adf[adf['Strike'] <= underlying_price + proximity_pts].copy()
            if not sup_rows.empty and 'PE_OI' in sup_rows.columns:
                sup_rows = sup_rows[sup_rows['PE_OI'] == sup_rows['PE_OI'].max()]
                if not sup_rows.empty:
                    sk = float(sup_rows.iloc[0]['Strike'])
                    oi = float(sup_rows.iloc[0]['PE_OI'])
                    strongest_sup = ('OC', f"₹{sk:.0f} OI:{oi/100000:.1f}L", sk, int(sk))
    except Exception:
        pass
    # Fallback to PCR levels if OC not available
    if strongest_res is None:
        for s in (pcr_sr_snapshot or []):
            sr_clean = s['type'].replace('🔴','').replace('🟢','').replace('⚪','').strip()
            if sr_clean == 'Resistance' and abs(underlying_price - s['level']) <= proximity_pts * 3:
                strongest_res = ('PCR', s['label'], s['level'], int(s['strike']))
                break
    if strongest_sup is None:
        for s in reversed(pcr_sr_snapshot or []):
            sr_clean = s['type'].replace('🔴','').replace('🟢','').replace('⚪','').strip()
            if sr_clean == 'Support' and abs(underlying_price - s['level']) <= proximity_pts * 3:
                strongest_sup = ('PCR', s['label'], s['level'], int(s['strike']))
                break

    candidate_res = [strongest_res] if strongest_res else []
    candidate_sup = [strongest_sup] if strongest_sup else []

    # ── Check ceiling rejection ───────────────────────────────────────────────
    for src, lbl, level, strike in candidate_res:
        if abs(underlying_price - level) > proximity_pts:
            continue
        key = f"rej_res_{level:.0f}"
        last_alerted = alerted.get(key)
        if last_alerted and (now - last_alerted).total_seconds() < 1800:
            continue
        # Count confirming signals
        signals = []
        if chart_bear:
            signals.append(f"📊 Chart: {_e(wick_detail) if wick_detail else _e(candle.get('pattern',''))}")
        oc_chg = oc_bear_strikes.get(float(strike), 0)
        if oc_chg:
            signals.append(f"📋 OC: CE ChgOI +{int(oc_chg/1000)}K at ₹{strike}")
        if float(strike) in depth_bear_strikes:
            signals.append(f"📉 Depth: Ask wall dominant at ₹{strike}")
        if len(signals) < 2:
            continue
        msg = f"🔴 REJECTION at ₹{level:.0f} ({len(signals)}/3) | Spot ₹{underlying_price:.0f} | {time_str}"
        alerted[key] = now
        return msg

    # ── Check floor bounce ────────────────────────────────────────────────────
    for src, lbl, level, strike in candidate_sup:
        if abs(underlying_price - level) > proximity_pts:
            continue
        key = f"rej_sup_{level:.0f}"
        last_alerted = alerted.get(key)
        if last_alerted and (now - last_alerted).total_seconds() < 1800:
            continue
        signals = []
        if chart_bull:
            signals.append(f"📊 Chart: {_e(wick_detail) if wick_detail else _e(candle.get('pattern',''))}")
        oc_chg = oc_bull_strikes.get(float(strike), 0)
        if oc_chg:
            signals.append(f"📋 OC: PE ChgOI +{int(oc_chg/1000)}K at ₹{strike}")
        if float(strike) in depth_bull_strikes:
            signals.append(f"📈 Depth: Bid wall dominant at ₹{strike}")
        if len(signals) < 2:
            continue
        msg = f"🟢 BOUNCE at ₹{level:.0f} ({len(signals)}/3) | Spot ₹{underlying_price:.0f} | {time_str}"
        alerted[key] = now
        return msg

    return None


def send_candle_pattern_alert(df, underlying_price, tf_label="5m"):
    """Fire Telegram alert when a notable bullish/bearish/indecision pattern forms
    on the most recently closed candle of the given timeframe. Dedup is per
    timeframe + candle timestamp + pattern so each closed candle alerts at most once."""
    if df is None or len(df) < 3 or not underlying_price:
        return None
    WATCH = {
        'Bullish': {
            'Hammer', 'Inverted Hammer', 'Bullish Engulfing', 'Bullish Harami',
            'Piercing Line', 'Tweezer Bottom', 'Morning Star',
            'Three White Soldiers', 'Bull Marubozu', 'Strong Green Candle',
        },
        'Bearish': {
            'Shooting Star', 'Bearish Engulfing', 'Bearish Harami',
            'Dark Cloud Cover', 'Tweezer Top', 'Evening Star',
            'Three Black Crows', 'Bear Marubozu', 'Strong Red Candle',
        },
        'Indecision': {'Doji', 'Spinning Top'},
    }
    try:
        cp = detect_candle_patterns(df, lookback=5)
    except Exception:
        return None
    pattern = cp.get('pattern')
    direction = cp.get('direction')
    if not pattern or pattern in ('No Pattern', 'Insufficient Data', 'Normal'):
        return None
    if pattern not in WATCH.get(direction, set()):
        return None
    try:
        last = df.iloc[-1]
        last_ts = last.get('datetime') if hasattr(last, 'get') else None
        if last_ts is None:
            last_ts = df.index[-1]
        ts_key = f"{tf_label}|{last_ts}"
    except Exception:
        ts_key = f"{tf_label}|{datetime.now(pytz.timezone('Asia/Kolkata')).strftime('%Y-%m-%d %H:%M')}"
    sent = st.session_state.setdefault('_candle_pattern_alerted', {})
    if sent.get(ts_key) == pattern:
        return None
    sent[ts_key] = pattern
    if len(sent) > 200:
        for k in list(sent.keys())[:-200]:
            sent.pop(k, None)
    emoji = '🟢' if direction == 'Bullish' else '🔴' if direction == 'Bearish' else '🟡'
    time_str = datetime.now(pytz.timezone('Asia/Kolkata')).strftime('%H:%M:%S IST')
    try:
        o, h, l, c = float(last['open']), float(last['high']), float(last['low']), float(last['close'])
    except Exception:
        o = h = l = c = 0.0
    return (
        f"🕯 <b>{tf_label} CANDLE — {pattern}</b> ({direction}) {emoji}\n"
        f"Spot ₹{underlying_price:.0f} | O:{o:.0f} H:{h:.0f} L:{l:.0f} C:{c:.0f} | {time_str}"
    )


def _find_pivots(df, left=3, right=3):
    """Return lists of (index, price) for pivot highs and pivot lows.
    A pivot high at i: high[i] is greater than all highs within ±left/right (exclusive)."""
    highs, lows = [], []
    if df is None or len(df) < left + right + 1:
        return highs, lows
    h = df['high'].values
    l = df['low'].values
    for i in range(left, len(df) - right):
        win_h = h[i - left:i + right + 1]
        win_l = l[i - left:i + right + 1]
        if h[i] == win_h.max() and (win_h == h[i]).sum() == 1:
            highs.append((i, float(h[i])))
        if l[i] == win_l.min() and (win_l == l[i]).sum() == 1:
            lows.append((i, float(l[i])))
    return highs, lows


def detect_chart_patterns(df, lookback=60, tol_pct=0.003):
    """Detect common multi-candle chart patterns from recent pivots.
    Returns dict {pattern, direction} or None. tol_pct is the level-match tolerance."""
    if df is None or len(df) < 20:
        return None
    recent = df.tail(lookback).reset_index(drop=True)
    highs, lows = _find_pivots(recent, left=3, right=3)
    if len(highs) < 2 and len(lows) < 2:
        return None

    def _close(a, b):
        ref = max(abs(a), abs(b), 1.0)
        return abs(a - b) / ref <= tol_pct

    last_h = highs[-3:] if len(highs) >= 3 else highs
    last_l = lows[-3:] if len(lows) >= 3 else lows

    # Head & Shoulders: 3 highs, middle highest, shoulders ~equal & below head, head meaningfully higher
    if len(highs) >= 3:
        s1, head, s2 = highs[-3][1], highs[-2][1], highs[-1][1]
        if head > s1 and head > s2 and _close(s1, s2) and (head - max(s1, s2)) / head > tol_pct:
            return {'pattern': 'Head & Shoulders', 'direction': 'Bearish'}

    # Inverse H&S: 3 lows, middle lowest, shoulders ~equal & above head
    if len(lows) >= 3:
        s1, head, s2 = lows[-3][1], lows[-2][1], lows[-1][1]
        if head < s1 and head < s2 and _close(s1, s2) and (min(s1, s2) - head) / head > tol_pct:
            return {'pattern': 'Inverse Head & Shoulders', 'direction': 'Bullish'}

    # Double Top: last two pivot highs at similar level, with a pivot low between them
    if len(highs) >= 2:
        h1_idx, h1 = highs[-2]
        h2_idx, h2 = highs[-1]
        if _close(h1, h2) and any(h1_idx < li < h2_idx for li, _ in lows):
            return {'pattern': 'Double Top', 'direction': 'Bearish'}

    # Double Bottom
    if len(lows) >= 2:
        l1_idx, l1 = lows[-2]
        l2_idx, l2 = lows[-1]
        if _close(l1, l2) and any(l1_idx < hi < l2_idx for hi, _ in highs):
            return {'pattern': 'Double Bottom', 'direction': 'Bullish'}

    # Triangles: need at least 2 recent highs and 2 recent lows
    if len(highs) >= 2 and len(lows) >= 2:
        h1, h2 = highs[-2][1], highs[-1][1]
        l1, l2 = lows[-2][1], lows[-1][1]
        highs_flat = _close(h1, h2)
        lows_flat = _close(l1, l2)
        highs_falling = (h1 - h2) / max(h1, 1.0) > tol_pct
        lows_rising = (l2 - l1) / max(l1, 1.0) > tol_pct
        if highs_flat and lows_rising:
            return {'pattern': 'Ascending Triangle', 'direction': 'Bullish'}
        if lows_flat and highs_falling:
            return {'pattern': 'Descending Triangle', 'direction': 'Bearish'}
        if highs_falling and lows_rising:
            return {'pattern': 'Symmetrical Triangle', 'direction': 'Neutral'}

    return None


def send_chart_pattern_alert(df, underlying_price, tf_label="5m"):
    """Fire Telegram alert when a multi-candle chart pattern (H&S, Double Top/Bottom,
    Triangle) is detected. Dedup per (timeframe + pattern) for 30 min so a slow-evolving
    pattern doesn't re-alert each cycle."""
    if df is None or len(df) < 20 or not underlying_price:
        return None
    try:
        res = detect_chart_patterns(df)
    except Exception:
        return None
    if not res:
        return None
    pattern = res['pattern']
    direction = res['direction']
    key = f"{tf_label}|{pattern}"
    sent = st.session_state.setdefault('_chart_pattern_alerted', {})
    now = datetime.now(pytz.timezone('Asia/Kolkata'))
    last = sent.get(key)
    if last and (now - last).total_seconds() < 1800:
        return None
    sent[key] = now
    emoji = '🟢' if direction == 'Bullish' else '🔴' if direction == 'Bearish' else '🟡'
    time_str = now.strftime('%H:%M:%S IST')
    return (
        f"📐 <b>{tf_label} CHART PATTERN — {pattern}</b> ({direction}) {emoji}\n"
        f"Spot ₹{underlying_price:.0f} | {time_str}"
    )


