                            if len(_oi_hist_s) >= 3 and _oi_str_s:
                                _sorted_ss = sorted(_oi_str_s)
                                _atm_i = len(_sorted_ss) // 2
                                for _soff, _slbl in [(-2, 'ATM-2'), (-1, 'ATM-1'), (0, 'ATM'), (1, 'ATM+1'), (2, 'ATM+2')]:
                                    _si2 = _atm_i + _soff
                                    if 0 <= _si2 < len(_sorted_ss):
                                        _sk = str(_sorted_ss[_si2])
