                                    for _soff, _slbl in [(-2, 'ATM-2'), (-1, 'ATM-1'), (0, 'ATM'), (1, 'ATM+1'), (2, 'ATM+2')]:
                                        _si2 = _ai2 + _soff
                                        if 0 <= _si2 < len(_slist2):
                                            _row2 = _dfs2[_dfs2['Strike'] == _slist2[_si2]]
